var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"어디로 갔나 했더니 여기 있었구나, 류드밀라?","JPN":"どこにいったのかと思っていたら、ここにいたのね、リュドミラ？","ENG":"I was wondering where you went to, Lyudmila.","TWN":"盧德米拉，我還想說你跑哪去了，原來在這裡。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"다른 애들이 함교에서 기다리는 중이야.","JPN":"子どもたちが艦橋で待っているわ。","ENG":"The others are waiting for you on the bridge.","TWN":"其他人都在艦橋上等著。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"연회 같은 건 싫어해도 건배사 할 때까진 동석하면 안 될까?","JPN":"宴会が嫌いなのはわかるけど、乾杯の挨拶まではいてくれないかしら？","ENG":"I know you hate parties, but can't you at least stay until the toast?","TWN":"我知道你不喜歡這種社交場合，但起碼待到致詞完吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"미안하군, 알렉스. 대원들의 노고를 치하하는 자리에 빠질 생각은 없었다.","JPN":"すまない、アレックス。隊員たちの苦労を労う席から抜け出すつもりはなかったんだが。","ENG":"Apologies, Alex. I did not intend to avoid an event where my comrades' hard work was being commended.","TWN":"抱歉，雅蕾克絲，我沒有要缺席慶功宴的意思。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"으음…… 일이 좀처럼 진척을 보이지 않으니 답답하군.","JPN":"ううむ……なかなかはかどらないからもどかしいな。","ENG":"Mm... It's frustrating because I cannot see any progress.","TWN":"只是……事情遲遲沒有進展，心情有點煩悶。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"응? 테이블 위의 그건 뭐야?","JPN":"うん？　テーブルにあるそれは何なの？","ENG":"Hmm? What's that on the table?","TWN":"嗯？桌上那是什麼東西？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"저건…… 제 생각이 맞다면 프라모델 같군요.","JPN":"あれは……おそらくプラモデルでしょう。","ENG":"I think... that's a plamodel.","TWN":"那是……我沒猜錯的話，應該是模型吧！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그렇다. 역시 눈썰미가 좋군, 예고르.","JPN":"その通り。すぐにわかるとはさすがだな、イェゴール。","ENG":"Correct. You have a keen eye, Yegor.","TWN":"沒錯，伊高爾的眼睛真利。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……정확히는 <color=#ffd34c>프라모델이었던 것</color>이라고 해야겠지만.","JPN":"……正確には<color=#ffd34c>プラモデルだったもの</color>というべきだが。","ENG":"...To be exact, it <color=#ffd34c>was a plamodel</color>.","TWN":"……但正確來說，應該是<color=#ffd34c>正常版的模型</color>。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"며칠 전에 이수연이 자기 집에서 귀한 브랜디를 개봉하자고 연락했다.","JPN":"数日前、カナミの方から自分の家で一緒に貴重なブランデーを開けないかと連絡があってな。","ENG":"A few days ago, Lee Sooyeon invited me to her home to open a precious bottle of brandy with her.","TWN":"前幾天李秀妍打給我，說她有一瓶高級的白蘭地，要找我去她家喝一杯。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"회사에 조금 일찍 도착하는 바람에, 일이 끝날 때까지 기다리고 있었다만…….","JPN":"会社に少し早く着いてしまって、仕事が終わるまで待っていたのだが……","ENG":"I had to wait for her to get off work as I arrived at the company earlier than expected...","TWN":"我那天有點早到公司，所以就在公司等她忙完……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"응? 이건……?","JPN":"ん？　これは……？","ENG":"Hmm? Isn't that...?","TWN":"嗯？這是……？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"재질로 보아…… 대원들이 말했던 프라모델이란 건가?","JPN":"材質から見て……これが隊員たちが話していたプラモデルというものか？","ENG":"Judging from the materials used... is this the plamodel they were talking about?","TWN":"看它的材質……這就是隊員們說的模型嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"작전기록 녹음.","JPN":"作戦記録、録音。","ENG":"Operation log.","TWN":"作戰紀錄錄音。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"코핀 컴퍼니 휴게실에서 조립된 프라모델을 발견했다.","JPN":"コフィンカンパニー休憩室で完成しているプラモデルを見つけた。","ENG":"I found an assembled plamodel in Coffin Company's break room.","TWN":"我在科芬公司的休息室裡發現組裝好的模型。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대원들의 이야기대로 실물만큼 정교하게 생겼군. 만들어 보고 싶은 욕구가 생길 정도다.","JPN":"隊員たちが話していたとおり、まるで実物のような精巧さだ。作ってみたいという欲求が湧いてくる。","ENG":"It looks as detailed as the real thing, just as they have told me. It makes me want to assemble one myself.","TWN":"確實就像隊員們所說的一樣，實品非常精緻，精緻到我也想動手做做看。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런데 프라모델의 형태가…… 누군가와 무척 닮은 것 같다.","JPN":"しかしこのプラモデルの形は……誰かによく似ている気がする。","ENG":"However, the shape of this model... looks very familiar to someone I know.","TWN":"不過那個模型的外觀……長得和某人非常像。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"정확한 판단을 위해 잠시 만져 보도록 하겠다.","JPN":"正確な判断を下すために、少しばかり触ってみるとしよう。","ENG":"To get a better assessment, I'll briefly touch it.","TWN":"因此我決定先摸摸看再做決定。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"오오, 관절부의 가동 범위가 경이롭군.","JPN":"おお、関節の可動域が驚異的なレベルだ。","ENG":"Ooh, the movement range of its joints is remarkable.","TWN":"哇喔，可以動的關節部分非常驚人。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이 부분은 제작자가 손수 도색한 건가. 평범한 물감이 아니군.","JPN":"この辺りは製作者が自ら塗装したのだろうか。ただの絵具でなさそうだな。","ENG":"Did the maker of this model paint this part themselves? It doesn't seem to be ordinary paint.","TWN":"這部分是組裝的人親手上色的嗎？似乎不是普通的顏料。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"침식체의 냄새……!","JPN":"侵食体の匂い……！","ENG":"I smell a C.O...!","TWN":"侵蝕體的味道……！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음? 너는 연회장에 있었던……?","JPN":"うん？　君は宴会場にいた……？","ENG":"Hmm? Aren't you the girl from the party...?","TWN":"嗯？你是在會場的……？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"침식체는……!","JPN":"侵食体は……！","ENG":"Corrupt Object...!","TWN":"侵蝕體……！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"박살낸다!!","JPN":"ぶっ壊す！！","ENG":"I must smash!","TWN":"粉碎！！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하아…… 하아……","JPN":"はぁ……はぁ……","ENG":"*Huff...* *Huff...*","TWN":"呼呼……呼呼……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이런 기습에 고전하다니, 나도 긴장이 느슨해졌나 보군.","JPN":"この程度の不意打ちに苦戦するとは、私も気がたるんでいたようだ。","ENG":"Struggling with an ambush like this... I must have lowered my guard too much.","TWN":"竟然會陷入苦戰，看來我的螺絲有點鬆了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"……천장에 붙어서 움직일 수가 없어.","JPN":"……天井にくっついて動けない。","ENG":"...I'm stuck on the ceiling. I can't move.","TWN":"……黏在天花板上，不能動。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"염동력으로 구속해 두었다. 힘으로 풀려고 하면 다칠 수 있으니 가만히 있어라.","JPN":"念動力で拘束した。無理やり抜けようとすれば怪我するから動かない方がいい。","ENG":"I restrained you with telekinesis. You'll get hurt if you try to free yourself by force, so I suggest you stay still.","TWN":"我用念力將你困住，要是用蠻力掙脫的話會受傷的，勸你不要輕舉妄動。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그나저나 침식파를 감지한 건가……. 이수연이 주의하라던 이유가 있었군.","JPN":"それにしても侵食波を感知したというのか……カナミが気を付けろと言うだけはある。","ENG":"But to detect Corruption rays... I understand why Lee Sooyeon told me to be careful.","TWN":"不過是有感應到侵蝕波嗎…… 所以李秀妍才會要我注意嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"침식체. 이상하게 냄새가 옅지만 알 수 있어.","JPN":"侵食体。なぜか匂いは薄いけど、わかる。","ENG":"C.O. The smell is weirdly faint, but I can tell.","TWN":"侵蝕體，奇怪，雖然味道淡淡的，卻可以知道。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카가 빨리 안 내려 주면 꼭 잡아먹겠대.","JPN":"オルカが言っている。早く降ろさなければ絶対に食べてやるって。","ENG":"Orca says that if you don't let me down now, she's going to eat you.","TWN":"奧爾卡說快放下來，否則吃掉你。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그건 곤란해. 나는 관리자……","JPN":"それは困るな。私は管理者……","ENG":"That's going to be difficult. The Administrator–","TWN":"辦不到，我要去替管理者……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"아니, 사장을 위해 해야 할 일이 있다.","JPN":"いや、社長のためにやるべきことがある。","ENG":"I mean, Boss, needs me to do something for him.","TWN":"不是，我要去替老闆辦點事。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"사장……?","JPN":"社長……？","ENG":"Boss...?","TWN":"老闆……？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"사장은 마시멜로를 많이 가지고 있어. 그러니까 좋은 기계야.","JPN":"社長はマシュマロをたくさん持っている。だから良いロボット。","ENG":"Boss has a lot of marshmallows. So he's a good machine.","TWN":"老闆有很多棉花糖，他是好機器人。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……그렇군. 나도 같은 생각이다.","JPN":"……そうか。私も同じ考えだ。","ENG":"...I see. I also think so too.","TWN":"……原來如此，我也同意。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"너에 대해서는 익히 들었다. 오르카.","JPN":"君については良く聞いている。オルカ。","ENG":"I heard a lot about you, Orca.","TWN":"我聽說過很多有關於你的事，奧爾卡。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그러니 여기서는 당분간 임시 휴전을 제안하도록 하지.","JPN":"だからここはいったん、暫定的な休戦としないか。","ENG":"So, I would like to propose a temporary truce.","TWN":"我建議暫時休兵 。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"휴전? 그게 뭐지?","JPN":"休戦？　それって何？","ENG":"Truce? What's that?","TWN":"休兵？那是什麼意思？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"으음. 언젠가 싸울 수도 있지만, 그 전까지는 서로 해치지 말자는 약속이다.","JPN":"ううむ、いつか戦ってもいいが、それまではお互いに攻撃しないことを約束することだ。","ENG":"Um, although we may fight one day, we won't harm each other for the time being.","TWN":"就是，之後要打還是可以打，但現在先暫時說好不要出手互相傷害。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"오르카, 너는 싸우면서 다치는 걸 좋아하나?","JPN":"オルカ、君は戦って傷つくことが好きか？","ENG":"Orca, do you like fighting and getting hurt?","TWN":"奧爾卡，你喜歡在打架中受傷嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"……금방 낫지만, 아픈 건 싫어.","JPN":"……すぐに治るけど、痛いのは嫌。","ENG":"...I heal fast, but I don't like pain.","TWN":"……雖然很快就會好起來，但會痛，我不喜歡。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그래. 싸우게 되면 양측 모두 아픈 상처를 입게 되지.","JPN":"だろう。戦ったらお互いが深い傷を負うことになってしまう。","ENG":"Yes. Fighting only leaves both sides with painful wounds.","TWN":"沒錯，要是我們打起來的話，雙方都會受傷對吧？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그렇기 때문에 싸움은 최후의 수단으로 남겨 둬야 한다.","JPN":"だからこそ戦いを選ぶのは最後の手段でなければならない。","ENG":"That's why fighting should only be a last resort.","TWN":"所以要把打架當成最後的手段。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"상처라면 벌써 입었다.","JPN":"傷ならもう負った。","ENG":"But pain has already been caused.","TWN":"已經受傷了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음? 제압할 때 부상은 입지 않았을 텐데……?","JPN":"うん？　制圧のときに負傷はさせなかったはずだが……？","ENG":"Hmm? But I did not injure you while subduing you…?","TWN":"嗯？我提出要休兵時你還沒受傷吧……？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"네가 들고 있던 저거.","JPN":"あなたが持っていた、あれ。","ENG":"That thing you were holding.","TWN":"你手裡拿的那個，"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"부서졌다.","JPN":"壊れた。","ENG":"It's broken.","TWN":"壞掉了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……앗.","JPN":"……あっ。","ENG":"...Ah.","TWN":"……啊。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"보급용 초콜릿으로 임시 휴전 조약은 체결했지만, 제압하는 과정에서 프라모델이 망가졌더군.","JPN":"補給用のチョコレートで暫定休戦協定は結べたが、制圧する際にプラモデルを壊してしまったのだ。","ENG":"I was able to form a truce with some chocolate rations, but I broke the plamodel while trying to subdue her.","TWN":"雖然我用補給巧克力說服她暫時休兵，但在交手過程中卻不慎弄壞了模型。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래서 고치러 가져온 거니? 사과하고 새로 하나 사도 됐을 텐데?","JPN":"それで直すために持って帰ってきたってこと？　謝って新しく買ってあげてもよかったんじゃない？","ENG":"So you brought it here to fix it? Couldn't you have apologized and bought her another one?","TWN":"所以你把它拿來是要修理它？不是道個歉再買一個新的就好了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런 방식은 프라모델의 주인이 완성하는 데 들인 정성을 무시하는 처사다.","JPN":"そんなやり方は持ち主がプラモデルを完成するまでにした苦労を無下にすることだ。","ENG":"That method undermines the effort the owner put into making this model.","TWN":"這樣的話，那模型的主人在組裝過程中付出的心血不就都白費了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"망가진 물건에도 가치는 있는 법이니까. 네가 입버릇처럼 하던 말 아니었나.","JPN":"壊れたモノにも価値はある。君の口癖ではないか。","ENG":"Even broken things have value. Isn't that what you keep telling me?","TWN":"壞掉的東西也是有價值的，這不是你常說的嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……무뚝뚝한 주제에 그런 점은 참 섬세하다니까.","JPN":"……あなたって無愛想なのに、そういうところは律儀よね。","ENG":"...For someone who is quite reserved, you are awfully keen at times.","TWN":"……平常看你一副沉默寡言的樣子，別人說的話倒是記得很清楚嘛。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"전대장님, 그럼 혹시 직접 고치실 겁니까?","JPN":"戦隊長殿、もしかして戦隊長殿自ら修復されるのですか？","ENG":"Commander, are you going to fix it yourself?","TWN":"戰隊長，所以你是打算自己修嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음? 그야 당연하지 않나.","JPN":"うん？　それは当たり前ではないか。","ENG":"Hmm? Of course.","TWN":"這什麼問題？不是當然的嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"전대장님이 직접 고치신다고요?","JPN":"戦隊長殿じきじきにですか？","ENG":"Are you going to fix it yourself, Commander?","TWN":"戰隊長要自己修嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"저희에게 맡겨 주십시오! 아니, 맡기셔야 합니다!","JPN":"私たちにお任せください！　いいえ、お任せいただかなくてはなりません！","ENG":"Leave it to us! No! You must let us handle it!","TWN":"請交給我們修理吧！不，是務必要交給我們！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"고맙지만 원본을 본 사람은 나밖에 없다.","JPN":"気持ちはありがたいが、元の状態を知っているのは私しかいない。","ENG":"Thank you, but I am the only one who knows what it originally looked like.","TWN":"你們的好意我心領了，但只有我看過原本的樣子。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"똑같이 만들 수 있어. 걱정하지 마라.","JPN":"元通りに直せる。心配するな。","ENG":"I will be able to make it whole. So do not worry.","TWN":"我一定會把它恢復原狀的，放心吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"얘가 쓸데없이 객기 부리네. 오르카란 애가 머리에 칼 꽂았나?","JPN":"変に意地を張るわね。オルカって子に頭でも刺されたのかしら？","ENG":"Why are you being so stubborn? Did this Orca kid plunge a knife into your head?","TWN":"她突然是在發什麼神經，是被那個叫奧爾卡的孩子打到頭嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님, 말씀이 너무 점잖으십니다. 이럴 때는 더 확실하게 말씀해 주셔야죠.","JPN":"副戦隊長殿、言い方が優しすぎます。こういう時はよりビシッとおっしゃっていただきませんと。","ENG":"Deputy Commander, you are being too gentle with her. You must state what you mean more clearly.","TWN":"副戰隊長，你話說得太婉轉了，這種時候要直接一點才對。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"크흠. 내 부주의로 망가뜨렸으니 내가 책임질 일이다.","JPN":"こほん。私の不注意で壊れてしまったのだ。私が責任を取らなければ。","ENG":"Ahem. It was my carelessness that broke it, so I will take the responsibility.","TWN":"咳咳，這是因為我個人的疏失才弄壞的，所以我要負責修好。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"사적인 용무에 부하들을 동원하긴 원치 않아. 이 건에 대해선 더는 언급하지 말도록.","JPN":"私的な用事に部下たちを巻き込みたくない。この件についてはこれ以上何も言わないでくれ。","ENG":"I do not want my subordinates to deal with my personal matters. End of discussion.","TWN":"我不希望公器私用，大家都不用再說了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"좋아.","JPN":"いいわ。","ENG":"Okay.","TWN":"好啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님?","JPN":"副戦隊長殿？","ENG":"Deputy Commander?","TWN":"副戰隊長？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"류드밀라, 예전에 침식지대에서 구출한 아이들에게 네가 만든 팔찌 줄 때 기억해?","JPN":"リュドミラ、以前侵食地帯から助け出した子どもたちにあなたの作ったブレスレットをプレゼントしたときのことを覚えてる？","ENG":"Lyudmila, do you remember the bracelets you made for the children you rescued from the Corrupted Area a long time ago?","TWN":"盧德米拉，你還記得有一次我們從侵蝕地區把孩子們救出來之後，你送他們你親手做的手環嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아이들이 울 때마다 네가 어떤 표정 지었는지 다들 알고 있어. 넌 신경 안 쓴다고 했지만.","JPN":"子どもたちが泣くたびにあなたがどんな顔をしていたかみんな知っているわ。あなたは気にならないと言っていたけど。","ENG":"Everyone here knows the expression you made whenever they cried. Even though you said you didn't care.","TWN":"雖然你都說你沒放在心上，但大家都有看到孩子哭的時候，你臉上的表情。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"으음…….","JPN":"ううむ……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"우리 애들도, 나도 네가 괴로워하지 않았으면 좋겠어. 지금도 충분히 힘들 테니까.","JPN":"みんなも私も、あなたには苦しんでほしくないと思っているの。今でも十分辛いでしょうから。","ENG":"The kids and I don't want to see you suffer. We all know it's been hard for you as it is.","TWN":"現在的情況就已經夠辛苦了，我們不希望你再因此而難過。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"하지만 스스로 책임지길 원한다면, 부관으로서 따라 줄게.","JPN":"でも自分で責任を取りたいというなら、副官として尊重するわ。","ENG":"But if you wish to take care of it on your own, I'll respect your decision as your deputy commander.","TWN":"不過要是你堅持負起這個責任，那身為副隊長，我會尊重你的決定。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……솔직하게 얘기해 줘서 고맙군, 알렉스.","JPN":"……正直に言ってくれてありがとう、アレックス。","ENG":"...Thank you for being honest, Alex.","TWN":"……謝謝你告訴我實話，雅蕾克絲。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"별말씀을. 전대장님.","JPN":"どういたしまして。戦隊長。","ENG":"Don't mention it, Commander.","TWN":"不客氣，戰隊長。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"작업에 집중하려면 조용한 편이 좋지? 우린 자리 비워 줄게.","JPN":"私たちがここにいない方が静かで作業に集中できるわね？","ENG":"It'll be better for you to focus in a quiet environment, right? We'll leave you alone then.","TWN":"在安靜的地方比較能專心作業吧，我們先出去。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님께서 그렇게 말씀하신다면……","JPN":"副戦隊長殿がそうおっしゃるのであれば……","ENG":"If Deputy Commander says so...","TWN":"既然副戰隊長都這麼說了……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"힘내십시오, 전대장님. 응원하겠습니다!","JPN":"ご健闘を、戦隊長殿。応援しております！","ENG":"Good luck, Commander! We will be rooting for you!","TWN":"戰隊長加油，我們精神上與你同在！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음! 맡겨 두도록!","JPN":"うむ！　任せておけ！","ENG":"Mm! Leave it to me!","TWN":"嗯！交給我吧！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"류드밀라, 아침이야.","JPN":"リュドミラ、朝よ。","ENG":"Lyudmila, it's morning.","TWN":"盧德米拉，天亮了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"으음…… 시간이 벌써 그렇게 됐나?","JPN":"ううん……もうそんな時間なのか？","ENG":"Mm... Is it already?","TWN":"呃嗯……時間過得這麼快？"},"stage":{"bg":"OFFICE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"설마 밤새 쉬지도 않고 만드신 겁니까?","JPN":"まさか徹夜で作っていらしたのですか？","ENG":"Did you stay up all night trying to fix it?","TWN":"戰隊長該不會是熬夜弄模型吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그래. 잠들 필요는 없다지만 프라모델 만들기는 상상 이상의 정신력이 필요하더군.","JPN":"ああ。眠る必要はないのだが、プラモデル作りというのは想像以上に精神力を消耗する作業なのだな。","ENG":"I believe so. Although I do not need to sleep, making a plamodel requires more focus than I imagined.","TWN":"沒錯，雖然我不需要睡覺，但沒想到做模型比想像中還費神呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"만드는 내내 교전을 방불케 하는 시간이었어. 정말 치열하면서 의미 있는 경험이었다.","JPN":"組み立てている間中、さながら交戦しているかのようだった。非常に熾烈で、良い経験をした。","ENG":"The whole process was similar to that of a skirmish. It was a fierce and meaningful experience.","TWN":"彷彿跟打仗一樣，真是一次既刺激又有意義的經驗。"},"stage":{"bg":"OFFICE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래서……","JPN":"それで……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"OFFICE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"이게 그 완성작이니?","JPN":"これは完成しているのかしら？","ENG":"Is this the finished product?","TWN":"那個就是完成品嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"이, 이건…….","JPN":"こ、これは……","ENG":"I-is this...","TWN":"這…就是…"},"stage":{"bg":"OFFICE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"프라모델…… 인 겁니까?","JPN":"プラモデル……なのでしょうか？","ENG":"really... a plamodel?","TWN":"模型……嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하나 양, 정말 꼭 이렇게까지 해야겠나?","JPN":"管理部長、本当にそこまでしなくちゃいけないのか？","ENG":"Miss Kim, do you really have to do this?","TWN":"荷娜，你真的有必要這樣嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"죄송해요, 사장님. 그래도 부사장님께 보고를 안 드릴 수는 없었어요.","JPN":"申し訳ありません、社長。しかし副社長に報告しないわけにはいかなかったので。","ENG":"I'm sorry, Boss. But I had to report this to the Vice President.","TWN":"很抱歉，老闆，但我還是必須呈報副總。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"머신 갑 트로피 같은 걸 잔뜩 만드시는 것까진 이해해 드렸지만……","JPN":"マシーン-甲-トロフィーのようなものをたくさん製作されていることには目を瞑りましたが……","ENG":"I can let you make tons of Machine G.A.P. trophies but…","TWN":"你想做很多機械·我超帥，到這裡我都還能理解……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"외부 업체와 협업해서 머신 갑 프라모델 생산이라니요. 이건 이미 회사 차원의 문제예요.","JPN":"外部の業者と提携してマシーン-甲-プラモデルの生産だなんて。これは個人を超えた会社の問題です。","ENG":"Creating a Machine G.A.P. plamodel by collaborating with another business? That makes this a company issue.","TWN":"但你竟然是要和外面的廠商合作生產機械·我超帥 模型，這已經是牽涉到公司層面的問題了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하나 양, 우리 그러지 말고 대화로 풀어나가는 게…….","JPN":"管理部長、そう言わずに対話で解決しないか……","ENG":"Miss Kim, let's try to talk this out–","TWN":"荷娜，你不要這樣，你先聽我解釋……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇군요. 그럼 어디 대화로 풀어 볼까요?","JPN":"そうですね。では対話で落としどころを探しましょうか。","ENG":"Very well. Why don't we talk this out, then?","TWN":"是嗎？你想解釋什麼？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_LONG","text":{"KOREA":"부, 부사장!","JPN":"ふ、副社長！","ENG":"V-Vice President!","TWN":"副，副總！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_LONG","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하나 씨에게 들었습니다. 저에게 일절 상의도 없이 외부 업체와 협업을 추진하셨다더군요.","JPN":"ナカシマさんから聞きました。私に一切相談せずに外部業者との提携を進められたそうですね。","ENG":"Miss Kim already told me that you partnered with another company without even telling me.","TWN":"荷娜都跟我說了，你沒跟我商量一聲，就擅自決定要和外部廠商合作。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"물론 회사의 이미지에 마이너스가 되지 않을 만큼 우수한 상품이겠죠?","JPN":"当然会社のイメージに傷がつかないような、優れた商品なんでしょうね？","ENG":"Of course, the product you made will be good enough to not harm the company's reputation, correct?","TWN":"想必跟老闆愛的那個長方形鐵桶不一樣，"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님께서 애지중지하시는 그 네모 깡통과 다르게 말입니다.","JPN":"社長が大切にしていらっしゃる、あの四角いボロ缶のようなものではなく。","ENG":"Unlike that square tin can you care so much about.","TWN":"是不會有損公司形象的優秀商品吧？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그, 그건 말일세……. 뭐랄지, 약간의 예술적 변주를 주긴 했지만서도……","JPN":"そ、それはだな……なんというか、若干の芸術的な捻りを加えたりはしたが……","ENG":"Th-that's... Well, I did put a slight artistic twist to it...","TWN":"這個嘛……該怎麼說呢，當然是會針對藝術性的部分做一些微調……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"괜찮습니다. 제 눈으로 직접 평가해 보죠.","JPN":"けっこうです。私がこの目で直接見て判断します。","ENG":"No matter. I will see for myself.","TWN":"沒關係，我親眼鑑定看看吧。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 휴게실에 숨겨 두신 거죠?","JPN":"この休憩室に隠しているんですね？","ENG":"You hid it in the break room, right?","TWN":"你把它藏在這間休息室裡對吧？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"부사장! 분명히 잘 팔릴 걸세! 내 안목은 자네가 가장 잘 알지 않나!","JPN":"副社長！　これはきっと売れる！　私の目の高さは君が一番良く知っているだろう！","ENG":"Vice President! It's going to sell like hot cakes! You know how good my insights are!","TWN":"副總！肯定會大賣的！你也知道我眼光很好的！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……그렇네요. 확실히.","JPN":"……そうですね。確かに。","ENG":"...Yes, you're right.","TWN":"……確實。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"응? 자네 지금 뭐라고 했나?","JPN":"ん？　今、なんと？","ENG":"Hmm? What did you say?","TWN":"蛤？你說什麼？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"확실히 이 정도면 협력 업체에서도 진지하게 검토해 볼 만하겠군요.","JPN":"確かにこのクォリティーなら、提携業者が前向きに検討するのもわかります。","ENG":"I believe the collaboration company would be enticed to consider this partnership with this kind of quality.","TWN":"以它的質感，廠商應該會有興趣談。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"프라모델이라고 했던가요? 양산하기에는 오히려 디테일이 지나치지 않을까 싶네요.","JPN":"プラモデル、と言いましたよね？　量産するには少しディテールが凝りすぎかと。","ENG":"Plamodel, was it called? But I think it's too detailed to be mass-produced.","TWN":"這是叫模型嗎？要量產的話，做工會不會太細？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"저, 정말인가? 정말 그 모델을 팔아도 된다는… 엥?","JPN":"ほ、本当か？　本当にそのモデルを売ってもいいと……え？","ENG":"R-really? Then does that mean we can sell this mod– Hmm?","TWN":"真，真的嗎？真的可以賣那個模型…嗯？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어라……?","JPN":"あれ……？","ENG":"Huh...?","TWN":"什麼……？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"참 안타깝군요. 평소에도 그 네모 깡통에 대한 집착만 버리시면 좋을 텐데 말이죠.","JPN":"非常に残念です。今回だけでなく、その四角いボロ缶への執着を捨てていただけるといいのですが。","ENG":"But what a pity. It would've been better if you stopped obsessing over that square tin can.","TWN":"真希望你平時也可以放下對那個長方形鐵桶的執著。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"언제 이렇게 정교한 타이탄 프라모델을 만들 생각을 하신 건가요?","JPN":"いつからこんな精巧なタイタンプラモデルを作る構想を練っておられたんですか？","ENG":"Since when did you think about making such a detailed model of Titan?","TWN":"你什麼時候開始有做這種精緻泰坦模型的想法的？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하하! 그렇지! 이것이야말로 세계 최고의 타이탄 프라모델 시제품이라네!","JPN":"あはは！　だろう！　これぞ世界最高のタイタンモデルの試作品なんだよ！","ENG":"Hah hah hah! Yes! This is the world's best Titan plamodel prototype!","TWN":"哈哈哈！沒錯！這就是全世界最棒的泰坦模型！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어떤가? 이 디테일은 기존 상품들과 비교할 수 없을 정도지!","JPN":"どうだ？　このディテールは今までの商品とは比べ物にならないだろう！","ENG":"What do you think? Its detail is incomparable to the ones already on the market!","TWN":"怎麼樣？這些細節是其他舊產品比不上的吧！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"좋습니다. 다만 미팅에는 저도 동석하기로 하죠.","JPN":"いいでしょう。ただし、商談には私も同席させてください。","ENG":"Very well. But I will also be attending the meeting.","TWN":"好吧，但條件是我也要一起參與會議。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇게 되었으니 업무 파악을 위해 자료 정리는 부탁드리겠습니다, 사장님.","JPN":"ということですので、業務把握のために資料の整理をお願いします、社長。","ENG":"Then Boss, please prepare the paperwork so I can review.","TWN":"開會需要準備資料吧，那就再麻煩老闆囉。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"들었나, 하나 양. 자료 정리 부탁하지.","JPN":"聞いたか、管理部長。資料の整理を頼む。","ENG":"You heard her, Miss Kim. Please prepare the paperwork.","TWN":"荷娜聽到沒，再麻煩你整理資料。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님께서 <color=#ffd34c>직접</color> 해 주시죠.","JPN":"社長が<color=#ffd34c>直接</color> やってください。","ENG":"No, I asked <color=#ffd34c>you</color> to do it, Boss.","TWN":"我是請老闆<color=#ffd34c>自己</color>預備。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아, 알겠네! 자료 정리 그런 거 금방 하지!","JPN":"わ、わかった！　資料整理などなんてことはない！","ENG":"O-okay! It'll be a piece of cake for me!","TWN":"喔～好！整理資料很快的！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼 먼저 가보겠습니다. 지난번 작전 건으로 검토해야 할 서류가 많아서요.","JPN":"では戻りますね。前回の作戦の件で目を通さなければいけない書類がたくさんありますから。","ENG":"Then, please excuse me. I have documents to review from our previous operation.","TWN":"那就先這樣，我還要去忙上次作戰後要討論的資料。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"후우…… 십 년 감수했군.","JPN":"ふう……寿命が縮むかと思った。","ENG":"Whew... That was a close one.","TWN":"呼……嚇死我了。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그런데 어떻게 머신 갑 프라모델이 타이탄으로 바뀐 거지?","JPN":"それにしても、どうしてマシーン-甲-プラモデルがタイタンに変わっていたんだ？","ENG":"But how did my Machine G.A.P. plamodel turn into a Titan?","TWN":"明明就是機械·我超帥模型，怎麼會變成泰坦？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"부품도 그대로인 것 같은데……. 혹시?","JPN":"部品は変わっていないが……もしや？","ENG":"The parts seem to be the same... Then?","TWN":"零件也都一樣……難道？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음, 카운터로서 가진 능력도 아닐 텐데, 대단하다면 대단하고 괴상하다면 괴상하군.","JPN":"うむ、カウンターとして授かっている能力でもないだろうに、凄いといえば凄いが、変わっているといえば変わっているな。","ENG":"Mm... I don't believe it's an ability from a Counter. But it is astonishing and weird at the same time.","TWN":"嗯，也不是制裁者的能力，真是想不透。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……작전기록 녹음. 파손된 프라모델은 성공적으로 복구했다.","JPN":"……作戦記録、録音。破損したプラモデルの修復に成功した。","ENG":"...Operation log. I successfully restored the broken plamodel.","TWN":"……作戰紀錄錄音。成功還原壞掉的模型。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"다들 마음에 들어하는 것 같아 다행이군.","JPN":"皆が気に入ってくれているようでなによりだ。","ENG":"I am glad that they seemed to like it.","TWN":"幸好大家好像都蠻滿意的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"어째서 다들 타이탄이라고 하는지는 불분명하지만……","JPN":"なぜ誰もがタイタンと言うのかは理解できないが……","ENG":"But it is a mystery why they all called it a Titan...","TWN":"只是不知道為何大家都說它是泰坦……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"역시 너였구나, 류드밀라.","JPN":"やっぱりあなただったのね、リュドミラ。","ENG":"So it was you, Lyudmila.","TWN":"盧德米拉，我就知道是你。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이, 이수연?!","JPN":"か、カナミ！？","ENG":"L-Lee Sooyeon?!","TWN":"李，李秀妍？！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"시제품을 보고 직감했어. 그 사람이 멀쩡한 물건을 들고 올 리 없으니까.","JPN":"試作品を見た時にピンときたの。あの人がまともなものを見せてくるわけがないもの。","ENG":"I knew it when I saw the prototype. You see, Boss isn't one to bring in something that decent.","TWN":"我看到那個東西就知道是你，他怎麼可能拿什麼正常的東西來。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사내에 그런 재주를 부릴 사람은 없지만, 네 손재주라면 가능하지.","JPN":"社内にあんなものを作れる才能がある人はいないけれど、あなたなら出来ると思って。","ENG":"I don't think there is anyone in the company with that kind of talent, but it would be possible with your dexterity.","TWN":"公司裡沒有人有這種本事，但你的話倒是有可能。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……면목이 없군. 하지만 수연이 널 속일 생각은 아니었다.","JPN":"……面目ない。しかしカナミ。君を騙すつもりではなかった。","ENG":"...I have no excuses. But I had no intention of deceiving you.","TWN":"……真丟人，不過秀妍，我沒有要騙你的意思。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사과 받을 생각 없으니까 내 집무실에서 잠시 쉬고 가.","JPN":"謝罪なんてする必要ないわ。それより少しだけ私の執務室に寄っていって。","ENG":"I don't want an apology from you, so just take some time in my office.","TWN":"我沒有怪你的意思，在我的辦公室休息一下再走吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"평소에 얼굴 보기 힘든데 이런 기회가 있을 때 시간을 보내야지.","JPN":"普段なかなか会えないんだし、こうやってチャンスがあるときに一緒に過ごしたいわ。","ENG":"It's hard enough to see you nowadays, so I want to spend time with you when it's possible.","TWN":"平時這麼難見到面，當然要把握機會聚一下。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"일이 바쁘다고 했던 것 같은데, 괜찮겠나?","JPN":"仕事が忙しいと聞いたが、大丈夫なのか？","ENG":"Are you sure? I heard you were busy.","TWN":"沒關係嗎？你不是說你很忙？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"바쁜 건 맞아. 그러니 네가 와서 조금이라도 도와줘야지.","JPN":"確かに忙しいわね。だからこそあなたが手伝わないとね。","ENG":"I am. That's why you're going to help me with something.","TWN":"確實，所以你要來幫我忙。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"항상 느끼지만 확실히 어른이 되긴 했군. 말솜씨로는 도저히 못 당하겠어.","JPN":"いつも思うが、もうすっかり大人だな。口の上手さではもう敵わない。","ENG":"I always had a feeling, but you really are an adult. I can never win against that tongue of yours.","TWN":"你真的是長大了呢，我說不過你。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네가 예전에 너무 조숙했던 것도 있고.","JPN":"昔のあなたが大人すぎたのもあるわよ。","ENG":"That's because you were precocious.","TWN":"是你以前比較早熟啦。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런데 어쩌다가 그 사람 일에 휘말린 거야?","JPN":"ところで、どうしてあの人のことに巻き込まれたの？","ENG":"But how did you get involved with someone like him?","TWN":"不過他怎麼會把你也一起扯進來？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"아, 실은 어제 널 기다리다가……","JPN":"あ、実は昨日君を待っていて……","ENG":"Oh, actually, I was waiting for you yesterday, and...","TWN":"是這樣的，我在等你的時候……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};